    [Parameter, EditorRequired]
    public IReadOnlyList<TodoListItemViewModel> Items { get; set; } = [];

    [Parameter]
    public bool Loading { get; set; }

    /// <summary>Aufgerufen wenn der User "Abschließen/Wiedereröffnen" klickt.</summary>
    [Parameter, EditorRequired]
    public EventCallback<TodoListItemViewModel> OnToggleStatus { get; set; }

