    private static Color GetStatusColor(TodoStatus status) => status switch
    {
        TodoStatus.Pending    => Color.Warning,
        TodoStatus.InProgress => Color.Info,
        TodoStatus.Completed  => Color.Success,
        TodoStatus.Cancelled  => Color.Error,
        _                                                => Color.Default
    };

    private static Color GetPriorityColor(TodoPriority priority) => priority switch
    {
        TodoPriority.Low      => Color.Default,
        TodoPriority.Medium   => Color.Info,
        TodoPriority.High     => Color.Warning,
        TodoPriority.Critical => Color.Error,
        _                                                => Color.Default
    };

